<?php
namespace App\Controllers;use App\Core\{Auth,Database,Request,Session,Validator,View};use App\Models\User;use PDOException;
final class AuthController{public function loginForm(Request$r):void{View::render('auth/login',['title'=>'Patient Login','old'=>[],'errors'=>[]]);}public function login(Request$r):void{$d=$r->all();$v=new Validator();if(!$v->validate($d,['email'=>'required|email','password'=>'required'])){View::render('auth/login',['title'=>'Patient Login','old'=>$d,'errors'=>$v->errors()]);return;}if(!Auth::attempt($d['email'],$d['password'])){View::render('auth/login',['title'=>'Patient Login','old'=>$d,'errors'=>['email'=>['Email or password is incorrect.']]]);return;}redirect(Auth::hasRole('admin')?'admin':'dashboard');}public function registerForm(Request$r):void{View::render('auth/register',['title'=>'Create Account','old'=>[],'errors'=>[]]);}public function register(Request$r):void{$d=$r->all();$v=new Validator();if(!$v->validate($d,['name'=>'required|min:2','email'=>'required|email','password'=>'required|min:8|confirmed'])){View::render('auth/register',['title'=>'Create Account','old'=>$d,'errors'=>$v->errors()]);return;}try{Database::connection()->beginTransaction();$id=User::create($d);User::assignRole($id,'patient');Database::connection()->commit();}catch(PDOException$e){if(Database::connection()->inTransaction())Database::connection()->rollBack();View::render('auth/register',['title'=>'Create Account','old'=>$d,'errors'=>['email'=>['Email or phone is already registered.']]]);return;}Auth::attempt($d['email'],$d['password']);redirect('dashboard');}public function logout(Request$r):void{Auth::logout();redirect();}}

